/* src/safe.c */
#include <stdio.h>
#include <string.h>

#define MSG_BUF_SIZE 128

void format_message(const char *user_input, int code) {
    char buf[MSG_BUF_SIZE];  /* line 8: static array - not inherently unsafe */

    /* line 12: SAFE - snprintf with sizeof prevents overflow */
    snprintf(buf, sizeof(buf), "[%d] %s", code, user_input);

    /* Additional safe operations */
    size_t len = strlen(buf);
    if (len > 0) {
        buf[len - 1] = '\n';
    }

    fputs(buf, stdout);
}
